package io.scanbot.sdk.reactnative.extensions

import android.content.res.Resources
import android.view.View
import android.view.View.MeasureSpec
import com.facebook.react.bridge.ReactContext
import com.facebook.react.uimanager.UIManagerHelper
import io.scanbot.sdk.reactnative.models.BaseEvent
import io.scanbot.sdk.reactnative.models.ComponentEvent
import io.scanbot.sdk.ui_v2.common.ScanbotColor
import io.scanbot.sdk.util.log.LoggerProvider

internal fun Int.toPx(resources: Resources): Int {
    return (this * resources.displayMetrics.density).toInt()
}

internal fun Double.toPx(resources: Resources): Int {
    return (this * resources.displayMetrics.density).toInt()
}

object Utils {

    fun tryToParseRGBAHexColor(colorString: String): Int? {
        return try {
            ScanbotColor(colorString, false).toAndroid()
        } catch (ex: Exception) {
            null
        }
    }
}

internal fun View.layoutView() {
    measure(
        MeasureSpec.makeMeasureSpec(measuredWidth, MeasureSpec.EXACTLY),
        MeasureSpec.makeMeasureSpec(measuredHeight, MeasureSpec.EXACTLY)
    )
    layout(left, top, right, bottom)
}

internal fun View.sendEvent(event: BaseEvent) {
    val surfaceId = UIManagerHelper.getSurfaceId(this)

    UIManagerHelper.getEventDispatcherForReactTag((context as ReactContext), id)
        ?.dispatchEvent(ComponentEvent(event, surfaceId, id))
}